11: class Http1HeaderValidator : public HeaderValidator {
12: public:
13:   Http1HeaderValidator(
14:       const envoy::extensions::http::header_validators::envoy_default::v3::HeaderValidatorConfig&
15:           config,
16:       ::Envoy::Http::Protocol protocol, ::Envoy::Http::HeaderValidatorStats& stats,
