28:   ::Envoy::Http::HeaderValidator::ValidationResult
29:   validateResponseTrailers(const ::Envoy::Http::ResponseTrailerMap& trailer_map);
30: 
31: protected:
32:   /**
33:    * Checks for presence of both Transfer-Encoding and Content-Length headers and
34:    * removes the Content-Length header iff the http1_protocol_options.allow_chunked_length
35:    * config options is true.
36:    * If the http1_protocol_options.allow_chunked_length is false a request with both
37:    * Transfer-Encoding and Content-Length headers is rejected in the validateRequestHeaders method.
38:    */
39:   void sanitizeContentLength(::Envoy::Http::RequestOrResponseHeaderMap& header_map);
40: 
41:   /**
42:    * Validate Transfer-Encoding and Content-Length headers.
43:    * HTTP/1.1 disallows a Transfer-Encoding and Content-Length headers,
44:    * https://www.rfc-editor.org/rfc/rfc9112.html#section-6.2:
45:    *
46:    * A sender MUST NOT send a Content-Length header field in any message that
47:    * contains a Transfer-Encoding header field.
48:    *
49:    * The http1_protocol_options.allow_chunked_length config setting can
50:    * override the RFC compliance to allow a Transfer-Encoding of "chunked" with
51:    * a Content-Length set. In this exception case, we remove the Content-Length
52:    * header in the transform[Request/Response]Headers() method.
53:    */
54:   ::Envoy::Http::HeaderValidator::ValidationResult validateContentLengthAndTransferEncoding(
55:       const ::Envoy::Http::RequestOrResponseHeaderMap& header_map);
56: 
57: private:
58:   /*
59:    * Validate the Transfer-Encoding header.
60:    */
61:   HeaderValueValidationResult
62:   validateTransferEncodingHeader(const ::Envoy::Http::HeaderString& value) const;
63: 
64:   HeaderEntryValidationResult validateRequestHeaderEntry(const ::Envoy::Http::HeaderString& key,
65:                                                          const ::Envoy::Http::HeaderString& value);
66: 
67:   HeaderEntryValidationResult validateResponseHeaderEntry(const ::Envoy::Http::HeaderString& key,
68:                                                           const ::Envoy::Http::HeaderString& value);
69: 
70:   // This method validates :path header value using character set that includes characters
71:   // that https://datatracker.ietf.org/doc/html/rfc3986#section-3.3 RFC is ambiguous about:
72:   //
73:   // " < > [ ] ^ ` { } \ | #
74:   //
75:   // This method is called iff `envoy.uhv.allow_non_compliant_characters_in_path` is
76:   // `true`, which is the default value. Note the default will be switched to `false` in the future
77:   // for standard compliance.
78:   HeaderValidator::HeaderValueValidationResult
79:   validatePathHeaderWithAdditionalCharacters(const ::Envoy::Http::HeaderString& path_header_value);
80: 
81:   // Chooses path validation method based on the value of the override flag that affects the
82:   // validation algorithm.
83:   HeaderValidatorFunction getPathValidationMethod();
84: 
85:   const HeaderValidatorMap request_header_validator_map_;
86: };
